(function (window, document) {
if (!window.XMPlayer) {
  window.XMPlayer = {};
}
var XMPlayer = window.XMPlayer;
if (!window.XMView) {
  window.XMView = {};
}
var XMView = window.XMView;

function loadXMAndInit(xmdata) {
  if (!XMPlayer.load(xmdata)) {
    return;
  }

  XMView.init();

  var playbutton = document.getElementById('xmplaypause');
  playbutton.innerHTML='Play';
  playbutton.onclick = function() {
    if (XMPlayer.playing) {
      XMPlayer.pause();
      playbutton.innerHTML='Play';
    } else {
      XMPlayer.play();
      playbutton.innerHTML='Pause';
    }
  };
  playbutton.disabled = false;

  return XMPlayer.xm;
}


window.onload = async function() {
  XMPlayer.init();
  var dataUrl = 'data:application/octet-stream;base64,'
  var XM = await (await fetch(dataUrl)).arrayBuffer();
  loadXMAndInit(XM)
};

})(window, document);
